mapper.select:
select id, process_Name, operator, surrogate, odate, sdate, edate, state 
from wf_surrogate
where id = #{id}

		select id, process_Name, operator, surrogate, odate, sdate, edate, state 
		from wf_surrogate
		where state = 1

            and operator in

                #{operator}



            and process_Name in

                #{name}



			and sdate <= #{operateTime} and edate >= #{operateTime}

		order by #{orderBy} #{order}
